import React, { useCallback, useMemo, useState } from 'react';
import { Select, dispatchAppToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatVnd } from '../../../utils/formatters';
import { MONTH_OPTIONS, YEAR_OPTIONS } from '../../../utils/exportExcel';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import erp from '../../../styles/erpPage.module.css';
import reportStyles from '../../../styles/erpReportPage.module.css';
import type { B01Row, B02Row, B03Row } from '../../../services/analytics/models';
import { AnalyticsReportShell, ReportTabBar, ReportTableWrap } from '../../../components/report';

const TEST_ID = 'erp-bao-cao-tai-chinh';
const PAGE_ID = 'baocao-tai-chinh';

const BaoCaoTaiChinhPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(now.getMonth() + 1);
  const [year, setYear] = useState(now.getFullYear());
  const [tab, setTab] = useState<'b01' | 'b02' | 'b03'>('b01');
  const [b01, setB01] = useState<B01Row[]>([]);
  const [b02, setB02] = useState<B02Row[]>([]);
  const [b03, setB03] = useState<B03Row[]>([]);
  const [loading, setLoading] = useState(false);

  const handleLoad = useCallback(() => {
    setLoading(true);
    const p = { month, year };
    const req =
      tab === 'b01'
        ? analyticsService.getB01Dn(p)
        : tab === 'b02'
          ? analyticsService.getB02Dn(p)
          : analyticsService.getB03Dn({ year });
    req
      .then(d => {
        if (tab === 'b01') setB01(d as B01Row[]);
        else if (tab === 'b02') setB02(d as B02Row[]);
        else setB03(d as B03Row[]);
      })
      .catch(err =>
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, 'Lỗi'),
          type: 'error',
        }),
      )
      .finally(() => setLoading(false));
  }, [month, year, tab, dispatch]);

  const rows = tab === 'b01' ? b01 : tab === 'b02' ? b02 : b03;
  const exportPath =
    tab === 'b01'
      ? '/reports/financial/b01-dn/export-excel'
      : tab === 'b02'
        ? '/reports/financial/b02-dn/export-excel'
        : '/reports/financial/b03-dn/export-excel';

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-month`,
        content: (
          <div className={erp.field}>
            <Select label="Tháng" value={String(month)} onChange={e => setMonth(Number(e.target.value))} options={MONTH_OPTIONS} size="small" />
          </div>
        ),
      },
      {
        testId: `${TEST_ID}-field-year`,
        content: (
          <div className={erp.field}>
            <Select label="Năm" value={String(year)} onChange={e => setYear(Number(e.target.value))} options={YEAR_OPTIONS} size="small" />
          </div>
        ),
      },
    ],
    [month, year],
  );

  return (
    <AnalyticsReportShell
      testId={TEST_ID}
      pageId={PAGE_ID}
      title="Báo cáo tài chính"
      titleIconClass="fas fa-file-invoice-dollar"
      loading={loading}
      hasData={rows.length > 0}
      filterItems={filterItems}
      onLoad={handleLoad}
      exportPath={exportPath}
      exportParams={tab === 'b03' ? { year } : { month, year }}
      exportFilename={`BC-TC-${tab}.xlsx`}
      tabBar={
        <ReportTabBar
          testId={TEST_ID}
          tabs={[
            { id: 'b01', label: 'B01' },
            { id: 'b02', label: 'B02' },
            { id: 'b03', label: 'B03' },
          ]}
          activeId={tab}
          onChange={id => setTab(id as 'b01' | 'b02' | 'b03')}
        />
      }
    >
      <ReportTableWrap testId={`${TEST_ID}-grid`}>
        <thead>
          <tr>
            <th>Chỉ tiêu</th>
            {tab === 'b01' ? (
              <>
                <th className={reportStyles.colRight}>Nợ ĐK</th>
                <th className={reportStyles.colRight}>Có ĐK</th>
                <th className={reportStyles.colRight}>Nợ CK</th>
                <th className={reportStyles.colRight}>Có CK</th>
              </>
            ) : (
              <>
                <th className={reportStyles.colRight}>Kỳ này</th>
                <th className={reportStyles.colRight}>Kỳ trước</th>
              </>
            )}
          </tr>
        </thead>
        <tbody>
          {tab === 'b01'
            ? b01.map((r, i) => (
                <tr key={i} className={r.isTotal ? reportStyles.rowTotal : undefined}>
                  <td>{r.code} — {r.name}</td>
                  <td className={reportStyles.colRight}>{formatVnd(r.openingDebit)}</td>
                  <td className={reportStyles.colRight}>{formatVnd(r.openingCredit)}</td>
                  <td className={reportStyles.colRight}>{formatVnd(r.closingDebit)}</td>
                  <td className={reportStyles.colRight}>{formatVnd(r.closingCredit)}</td>
                </tr>
              ))
            : tab === 'b02'
              ? b02.map((r, i) => (
                  <tr key={i} className={r.isTotal ? reportStyles.rowTotal : undefined}>
                    <td>{r.code} — {r.name}</td>
                    <td className={reportStyles.colRight}>{formatVnd(r.currentAmount)}</td>
                    <td className={reportStyles.colRight}>{formatVnd(r.previousAmount)}</td>
                  </tr>
                ))
              : b03.map((r, i) => (
                  <tr key={i} className={r.isTotal ? reportStyles.rowTotal : undefined}>
                    <td>{r.code} — {r.name}</td>
                    <td className={reportStyles.colRight}>{formatVnd(r.currentAmount)}</td>
                    <td className={reportStyles.colRight}>{formatVnd(r.previousAmount)}</td>
                  </tr>
                ))}
        </tbody>
      </ReportTableWrap>
    </AnalyticsReportShell>
  );
};

export default BaoCaoTaiChinhPage;
